column.value:
{
  "pageDescription": "Processing and Quality Control - Media Preparation and Sample Processing",
  "sections": {
    "preparationForProcessing": {
      "title": "Preparation for Processing",
      "cultureMediaPreparation": {
        "mediaType": {"type": "choice", "label": "Media Type", "options": ["BLOOD_AGAR", "MACCONKEY", "SABOURAUD", "CHOCOLATE_AGAR", "MUELLER_HINTON", "XLD", "SS_AGAR", "TCBS", "MANNITOL_SALT", "EMB", "CLED", "OTHER"], "required": true},
        "batchNumber": {"type": "text", "label": "Batch Number", "required": true},
        "preparationDate": {"type": "date", "label": "Preparation Date", "required": true},
        "expiryDate": {"type": "date", "label": "Expiry Date", "required": true},
        "sterilityTestResult": {"type": "choice", "label": "Sterility Test Result", "options": ["Pass", "Fail", "Pending"], "required": true},
        "growthSupportResult": {"type": "choice", "label": "Growth Support Test Result", "options": ["Pass", "Fail", "Pending"], "required": true},
        "growthSupportOrganism": {"type": "text", "label": "Control Organism Used", "required": false}
      },
      "biochemicalMediaPreparation": {
        "mediaType": {"type": "choice", "label": "Media Type", "options": ["TSI", "UREASE", "CITRATE", "INDOLE", "MR_VP", "MOTILITY", "LYSINE", "ORNITHINE", "OXIDASE", "CATALASE", "COAGULASE", "OTHER"], "required": true},
        "batchNumber": {"type": "text", "label": "Batch Number", "required": true},
        "preparationDate": {"type": "date", "label": "Preparation Date", "required": true},
        "expiryDate": {"type": "date", "label": "Expiry Date", "required": true},
        "sterilityTestResult": {"type": "choice", "label": "Sterility Test Result", "options": ["Pass", "Fail", "Pending"], "required": true},
        "reactivityTestResult": {"type": "choice", "label": "Reactivity Test Result", "options": ["Pass", "Fail", "Pending"], "required": true},
        "reactivityTestOrganism": {"type": "text", "label": "Control Organism Used", "required": false}
      },
      "antibioticDiscIQC": {
        "discType": {"type": "choice", "label": "Disc Type", "options": ["AMP_10", "AMC_30", "GEN_10", "CIP_5", "CTX_30", "CAZ_30", "MEM_10", "VAN_30", "ERY_15", "TET_30", "SXT_25", "CHL_30", "OTHER"], "required": true},
        "lotNumber": {"type": "text", "label": "Lot Number", "required": true},
        "expiryDate": {"type": "date", "label": "Expiry Date", "required": true},
        "atccStrain": {"type": "choice", "label": "ATCC Control Strain", "options": ["ECOLI_25922", "STAPH_25923", "PSEUDO_27853", "ENTERO_29212", "KLEBSIELLA_700603", "OTHER"], "required": true},
        "zoneDiameter": {"type": "number", "label": "Zone Diameter (mm)", "required": true},
        "expectedRangeMin": {"type": "number", "label": "Expected Range Min (mm)", "required": false},
        "expectedRangeMax": {"type": "number", "label": "Expected Range Max (mm)", "required": false},
        "iqcResult": {"type": "choice", "label": "IQC Result", "options": ["Pass", "Fail", "Pending"], "required": true}
      },
      "enrichmentIncubation": {
        "enrichmentRequired": {"type": "boolean", "label": "Enrichment Required", "required": false},
        "enrichmentMedium": {"type": "choice", "label": "Enrichment Medium", "options": ["SELENITE_F", "TETRATHIONATE", "RAPPAPORT", "BHI", "THIOGLYCOLLATE", "ALKALINE_PEPTONE", "BUFFERED_PEPTONE", "TRYPTIC_SOY", "OTHER"], "required": false},
        "incubationCondition": {"type": "choice", "label": "Incubation Condition", "options": ["AEROBIC_37", "AEROBIC_35", "CO2_37", "ANAEROBIC_37", "MICROAEROPHILIC", "ROOM_TEMP", "REFRIGERATED", "OTHER"], "required": false},
        "incubationDuration": {"type": "text", "label": "Incubation Duration", "description": "e.g., 18-24 hours", "required": false}
      },
      "inventoryTracking": {
        "enabled": true,
        "trackLotNumbers": true,
        "trackExpiryDates": true,
        "trackStockLevels": true,
        "alertOnExpiry": true,
        "alertOnLowStock": true
      }
    },
    "processingAndQC": {
      "title": "Processing and Quality Control",
      "gramStaining": {
        "performed": {"type": "boolean", "label": "Gram Stain Performed", "required": false},
        "result": {"type": "choice", "label": "Gram Stain Result", "options": ["GRAM_POS_COCCI", "GRAM_POS_BACILLI", "GRAM_NEG_COCCI", "GRAM_NEG_BACILLI", "MIXED_FLORA", "NO_ORGANISMS", "YEAST", "OTHER"], "required": false},
        "performedBy": {"type": "text", "label": "Performed By", "required": false},
        "date": {"type": "date", "label": "Date", "required": false}
      },
      "microscopyExamination": {
        "performed": {"type": "boolean", "label": "Microscopy Performed", "required": false},
        "findings": {"type": "text", "label": "Microscopy Findings", "multiline": true, "required": false},
        "preliminaryIdentification": {"type": "text", "label": "Preliminary Identification", "required": false},
        "performedBy": {"type": "text", "label": "Performed By", "required": false}
      },
      "inoculation": {
        "performed": {"type": "boolean", "label": "Inoculation Performed", "required": false},
        "mediaUsed": {"type": "multiselect", "label": "Culture Media Used", "options": ["BLOOD_AGAR", "MACCONKEY", "SABOURAUD", "CHOCOLATE_AGAR", "MUELLER_HINTON", "XLD", "SS_AGAR", "TCBS", "MANNITOL_SALT", "EMB", "CLED", "OTHER"], "required": false},
        "inoculationDate": {"type": "date", "label": "Inoculation Date", "required": false},
        "performedBy": {"type": "text", "label": "Performed By", "required": false}
      },
      "incubation": {
        "started": {"type": "boolean", "label": "Incubation Started", "required": false},
        "condition": {"type": "choice", "label": "Incubation Condition", "options": ["AEROBIC_37", "AEROBIC_35", "CO2_37", "ANAEROBIC_37", "MICROAEROPHILIC", "ROOM_TEMP", "REFRIGERATED", "OTHER"], "required": false},
        "duration": {"type": "text", "label": "Duration (hours)", "description": "18-48 hours organism-dependent", "required": false},
        "expectedReadTime": {"type": "dateTime", "label": "Expected Read Time", "required": false}
      },
      "qualityControl": {
        "qcResult": {"type": "choice", "label": "QC Result", "options": ["Pass", "Fail"], "required": false},
        "failureReason": {"type": "choice", "label": "Failure Reason", "options": ["CONTAMINATION", "NO_GROWTH", "POOR_ISOLATION", "MEDIA_FAILURE", "TEMPERATURE_DEVIATION", "TECHNICAL_ERROR", "SAMPLE_QUALITY", "OTHER"], "required": false},
        "retakeRequired": {"type": "boolean", "label": "Retake Required", "required": false},
        "retakeAttempt": {"type": "number", "label": "Retake Attempt Number", "required": false},
        "notes": {"type": "text", "label": "Notes", "multiline": true, "required": false}
      }
    }
  },
  "systemActions": [
    "Record media preparation with IQC results",
    "Track antibiotic disc IQC with ATCC control strains",
    "Update sample processing status",
    "Flag QC failures and enable retake workflow",
    "Alert on media/reagent expiry and low stock"
  ],
  "statusTransitions": {
    "onQCPass": "COMPLETED",
    "onQCFail": "REJECTED",
    "onRetake": "IN_PROGRESS"
  },
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["gramStainResult", "inoculatedMedia", "incubationCondition", "qcResult"]
  },
  "previousPage": "Temporary Storage Assignment",
  "nextPage": "Culture & Identification"
}
